import Header from "../../components/Header/Header";
import classes from "./Chat.module.css";
import ChatForm from "../../components/Chat/ChatForm";
import { useState, useEffect } from "react";
import ChatMessage from "../../components/Chat/ChatMessage";

const Chat = (props) => {
  useEffect(() => {
    fetch("/channels/direct-messages", {
      headers: {
        Authorization: "Bearer " + props.token,
      },
    });
  }, []);

  const MESSAGES = [
    { message_id: 1, user_id: 1, user: "Bob", message: "Yo", time: "" },
    { message_id: 2, user_id: 2, user: "Eric", message: "Hello", time: "" },
    // { message_id: 3, user_id: 1, user: "Bob", message: "How are you doing", time: "" },
    // { message_id: 4, user_id: 2, user: "Eric", message: "I'm Good", time: "" },
    // { message_id: 5, user_id: 1, user: "Bob", message: "Nice", time: "" },
  ];

  const [messages, setMessages] = useState(MESSAGES);

  return (
    <div className={`${classes["chat-page"]} ${classes["container"]}`}>
      <Header
        title="Bob"
        avatar="https://animedao.to/images/call-of-the-night.jpg"
        tabBar={false}
      ></Header>
      <div className={classes["messages-wrapper"]}>
        <ol>
          {MESSAGES.map((item) => (
            <ChatMessage
              key={item.message_id}
              message={item.message}
              user={item.user}
              avatar="https://animedao.to/images/call-of-the-night.jpg"
            ></ChatMessage>
          ))}
        </ol>
      </div>
      <ChatForm></ChatForm>
    </div>
  );
};

export default Chat;
